SELECT picture
FROM work
WHERE team_id = #{teamId}
  AND competition_id = #{competitionId}

SELECT un.name
FROM user u
         JOIN university un ON u.school_id = un.id
WHERE u.id = (
    SELECT user_id
    FROM team_user
    WHERE team_id = #{teamId}
      AND status = #{captain}
    limit 1
)
